THE RISK:
{
 "id": "framework-agreements-hollow-large-operator-cell",
 "title": "Global framework agreements and bundled fit-outs foreclose the 0.40 large-operator cell the whole GTM is aimed at",
 "narrative": "The venture's stated first buyer is large operators, and cust.operator-large carries the biggest single channel weight (0.40) — a needs-source internal estimate with two-decimal precision. The corpus shows what that cell actually looks like from inside procurement: PDU spend at large operators flows through multi-year global framework agreements and integrated rack/power/cooling bundles (Digital Realty–Schneider style frameworks, all-in integrator contracts), not discrete PDU line items a regional entrant can bid. If half the 0.40 is procured this way, the model's most reachable-looking cell is structurally closed in Year 1 — and the conservative 1% obtainableFactor is being applied to a SAM that contains spend no entrant can contest at any price.",
 "category": "competitive",
 "targetNodes": [
  "cust.operator-large"
 ],
 "mechanism": [
  {
   "step": "trigger",
   "text": "Large operators consolidate power-equipment purchasing into global frameworks and integrator bundles; Vertiv's own partner material lists hyperscalers, telcos and colo REITs as house accounts under standing agreements",
   "refs": [
    "digest:cust-mix#c12",
    "ledger:cust.operator-large"
   ]
  },
  {
   "step": "propagation",
   "text": "The 0.40 share was derived from 'hyperscale+colo ≈ 62% buy direct' — but the only quantitative datapoint behind the channel axis (a supplier's 30%-of-orders figure) measures DC exposure, not buyer-type contestability, and no source quantifies what fraction of 'direct' spend is framework-locked",
   "refs": [
    "digest:cust-mix#c0",
    "ledger:cust.operator-large"
   ]
  },
  {
   "step": "model-impact",
   "text": "The contestable portion of the large-operator cell is materially below 0.40; SAM built on the full cell overstates reachable spend for the profile's chosen first buyer, and Year-1 pipeline math against it fails silently",
   "refs": [
    "ledger:cust.operator-large",
    "profile:Who is the primary buyer you'll sell through first?",
    "ledger:serviceableFactor"
   ]
  }
 ],
 "whyMissable": "'Large operators buy direct' is the founder's own GTM answer, and 0.40 looks like the biggest, most accessible cell. The surface appearance is a channel decision already made; what it hides is that 'direct' at these accounts means procured inside integrated frameworks the entrant cannot bid into — the cell exists, but not for them.",
 "expectedObviousness": "low",
 "falsifier": "Three or more CE large-operator PDU procurements in the next 12 months run as discrete, multi-vendor bake-offs and won by vendors outside the incumbent framework holders.",
 "likelihood": {
  "value": 0.48,
  "rationale": "Every procurement case study retrieved (Jülich, Schneider–Foxconn, Iren–Dell, Digital Realty–Schneider) shows bundled or framework purchasing; no counter-example of a contested standalone PDU line at a large operator surfaced in any search pass. Uncertainty is about the foreclosed fraction, not the mechanism. [evidence revision: The framework/bundle mechanism is strongly corroborated by the Digital Realty–Schneider SCA and Eaton bundle, marginally raising confidence. But the same DR release explicitly preserves a 'dynamic, multi-vendor environment,' and discrete competitive PDU tenders demonstrably exist (Utah, China Unicom) — showing framework-locking is not total. Since the load-bearing uncertainty is the foreclosed *fraction* (unquantified in all sources) rather than the mechanism's existence, only a small upward adjustment is warranted.]",
  "basis": "evidence",
  "revisedFrom": 0.45
 },
 "perturbation": [
  {
   "nodeId": "cust.operator-large",
   "op": "set",
   "value": 0.18,
   "note": "Framework- and bundle-foreclosed portion (~half) of the direct large-operator cell removed from contestable spend; siblings deliberately not re-normalized — this is absolute shrinkage of reachable spend, not a mix-shift"
  }
 ],
 "indicators": [
  {
   "signal": "Structure of large-operator PDU procurement: discrete lots vs bundled fit-out packages",
   "where": "TED (Tenders Electronic Daily) filtered for PDU/rack-power CPV codes in DE/NL/PL; Digital Realty and Equinix supplier-announcement pages",
   "threshold": "<2 standalone, multi-bidder PDU lots from CE large operators over two consecutive quarters",
   "updates": "increases"
  },
  {
   "signal": "New or renewed multi-year power-infrastructure framework agreements between colo REITs/hyperscalers and Schneider/Vertiv/Eaton",
   "where": "Schneider and Vertiv quarterly earnings calls and press rooms; operator capex-call commentary",
   "threshold": "≥2 new CE-relevant frameworks announced in 12 months",
   "updates": "increases"
  },
  {
   "signal": "Approved-vendor-list (AVL) openings at CE colocation operators",
   "where": "Operator supplier-qualification portals (Equinix, NTT, Data4, Atman)",
   "threshold": "Any AVL round explicitly inviting new rack-PDU vendors",
   "updates": "decreases"
  }
 ],
 "mitigations": [
  {
   "action": "Run 5 structured procurement interviews at CE large operators to split the 0.40 cell into framework-locked vs contestable spend",
   "type": "information",
   "voiNodeId": "cust.operator-large",
   "note": "Directly replaces the unsourced 0.40 with an evidence-based contestable share — the single highest-leverage number for the stated GTM"
  },
  {
   "action": "Re-sequence Year-1 GTM toward mid-market colo and enterprise retrofit, where discrete PDU purchasing is documented, and treat large operators as a Year-2+ AVL-qualification play",
   "type": "strategic",
   "voiNodeId": null,
   "note": "Aligns the ramp with the cells that are actually contestable pre-brand"
  },
  {
   "action": "Pursue sub-supplier status inside one integrator's bundle (rack integrator or fit-out contractor) rather than competing against the bundle",
   "type": "contractual",
   "voiNodeId": null,
   "note": "Converts the foreclosure mechanism into a channel"
  }
 ],
 "evidenceStatus": "corroborated",
 "evidence": [
  {
   "title": "Schneider Electric and Digital Realty Announce $373M Supply Capacity Agreement",
   "sourceType": "industry-report",
   "publisher": "Schneider Electric / PRNewswire",
   "date": "2025-11-19",
   "excerpt": "Digital Realty has signed a $373 million Supply Capacity Agreement (SCA) for UPS, Low Voltage Switchgear, and Pre-Fabricated Skids. The strategic shift to an SCA model provides guaranteed capacity and economies of scale, while preserving flexibility for a dynamic, multi-vendor environment.",
   "url": "https://www.prnewswire.com/news-releases/schneider-electric-and-digital-realty-announce-373m-supply-capacity-agreement-to-meet-rising-data-center-demand-302620427.html",
   "attached": true
  },
  {
   "title": "Colocation provider standardizes with Eaton for full solution suite",
   "sourceType": "industry-report",
   "publisher": "Eaton",
   "date": null,
   "excerpt": "Eaton supplied the colocation provider with complementary data center solutions including racks and PDUs as part of a standardized full solution suite deployed across all data center locations.",
   "url": "https://www.eaton.com/content/dam/eaton/products/backup-power-ups-surge-it-power-distribution/backup-power-ups/power-xpert-9395/9395p/dc-blox-success-story/eaton-dc-blox-success-story-CS153091EN.pdf",
   "attached": true
  },
  {
   "title": "Enlogic Power Distribution Units bid result / China Unicom PDU inquiry",
   "sourceType": "triangulation",
   "publisher": "UtahBids / 乙方宝",
   "date": "2025-06-05",
   "excerpt": "Discrete competitive PDU procurements do occur — Intellivex won University of Utah's Enlogic PDU solicitation via open bid; China Unicom Shanghai ran a discrete inquiry for 320 PDUs — but these are university/telco-regional buyers, not the hyperscale/colo direct-buy cell.",
   "url": "https://www.utahbids.net/bid-result/enlogic_power_distribution_units-14182081",
   "attached": true
  }
 ],
 "stances": [
  {
   "url": "https://www.se.com/us/en/about-us/newsroom/news/press-releases/schneider-electric-and-digital-realty-announce-373m-supply-capacity-agreement-to-meet-rising-data-center-demand-691d192005c0c16f5902ca3c",
   "stance": "supports",
   "quote": "Schneider Electric and Digital Realty Announce $373M Supply Capacity Agreement to Meet Rising Data Center Demand"
  },
  {
   "url": "https://www.prnewswire.com/news-releases/schneider-electric-and-digital-realty-announce-373m-supply-capacity-agreement-to-meet-rising-data-center-demand-302620427.html",
   "stance": "supports",
   "quote": "The strategic shift to an SCA model provides guaranteed capacity, economies of scale, and a dedicated LVS production line, while preserving the flexibility needed for a dynamic, multi-vendor environment to mitigate risk."
  },
  {
   "url": "https://www.datacenterdynamics.com/en/news/digital-realty-signs-373m-data-center-power-kit-deal-with-schneider-electric/",
   "stance": "supports",
   "quote": "Colo giant Digital Realty has signed a $373 million supply capacity agreement (SCA) with Schneider Electric for data center power equipment."
  },
  {
   "url": "https://doi.org/10.51219/jaimld/soumya-remella/601",
   "stance": "supports",
   "quote": "Traditional procurement models, focused on cost and predictability, are ill-suited to the demands of hyperscale build-outs, which require speed, resilience, and supplier accountability. This paper examines how sourcing strategies, contracting frameworks, and supplier partnerships accelerate delivery"
  },
  {
   "url": "https://www.utahbids.net/bid-result/enlogic_power_distribution_units-14182081",
   "stance": "contradicts",
   "quote": "Intellivex Data Center Solutions is the apparent low bidder on the University of Utah - Purchasing's Enlogic Power Distribution Units solicitation, with a low bid of $129,775.09 USD. Bids were opened on June 5, 2025"
  },
  {
   "url": "https://www.yfbzb.com/inviteBid/detail/20260420_590927703.html",
   "stance": "contradicts",
   "quote": "本询比采购项目为2026年中国联通上海基础设施运营中心UPS配电柜及PDU采购...2台UPS进线柜、2台UPS出线柜、320条PDU"
  },
  {
   "url": "https://www.eaton.com/content/dam/eaton/products/backup-power-ups-surge-it-power-distribution/backup-power-ups/power-xpert-9395/9395p/dc-blox-success-story/eaton-dc-blox-success-story-CS153091EN.pdf",
   "stance": "supports",
   "quote": "Eaton not only delivered a UPS offering unparalleled reliability, footprint and efficiency, but was also able to supply the colocation provider with complementary data center solutions including racks and PDUs."
  }
 ]
}

